import { inject, Injectable } from '@angular/core';
import { SupabaseService } from './Base/supabase.service';

@Injectable({ providedIn: 'root' })
export class StatisticsService {
  private supabaseService = inject(SupabaseService);

  // ===== 1. ORDINI DI OGGI (basati su order_headers) =====
  async getTodayOrders(): Promise<{ count: number; revenue: number }> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return { count: 0, revenue: 0 };

      const today = new Date().toISOString().split('T')[0];
      
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('order_headers')
        .select('total_amount, status, comande(total_amount)')
        .eq('restaurant_id', restaurantId)
        .eq('status', 'completed')
        .gte('created_at', `${today}T00:00:00`)
        .lte('created_at', `${today}T23:59:59`);

      if (error) throw error;

      // Calcola il totale dalle comande
      let revenue = 0;
      const headers = data || [];
      
      for (const header of headers) {
        if (header.comande && Array.isArray(header.comande)) {
          revenue += header.comande.reduce((sum: number, comanda: any) => 
            sum + (Number(comanda.total_amount) || 0), 0
          );
        }
      }
      
      return { count: headers.length, revenue };
    } catch (error) {
      console.error('Error in getTodayOrders:', error);
      return { count: 0, revenue: 0 };
    }
  }

  // ===== 2. VENDITE ULTIMI 7 GIORNI (basate su comande) =====
  async getLast7DaysSales(): Promise<{ day: string; amount: number }[]> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return this.generateEmptySalesData();

      const end = new Date();
      const start = new Date();
      start.setDate(start.getDate() - 6);

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('comande')
        .select('created_at, total_amount, status')
        .eq('restaurant_id', restaurantId)
        .eq('status', 'completed')
        .gte('created_at', start.toISOString())
        .lte('created_at', end.toISOString());

      if (error) throw error;

      return this.groupSalesByDay(data || [], start, end);
    } catch (error) {
      console.error('Error in getLast7DaysSales:', error);
      return this.generateEmptySalesData();
    }
  }

  // ===== 3. PIATTI PIÙ VENDUTI (basati su order_items) =====
  async getTopDishes(limit: number = 5): Promise<any[]> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return [];

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .rpc('get_top_dishes', { 
          p_restaurant_id: restaurantId,
          p_limit: limit
        });

      if (error) {
        // Fallback: query manuale se la funzione RPC non esiste
        return await this.getTopDishesFallback(restaurantId, limit);
      }

      return data || [];
    } catch (error) {
      console.error('Error in getTopDishes:', error);
      return [];
    }
  }

  // Fallback per top dishes
  private async getTopDishesFallback(restaurantId: string, limit: number): Promise<any[]> {
    try {
      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('order_items')
        .select(`
          quantity,
          dish:dish_id (
            id,
            name,
            base_price
          )
        `)
        .eq('restaurant_id', restaurantId);

      if (error) throw error;

      const dishMap = new Map<string, { name: string; quantity: number; revenue: number }>();
      
      (data || []).forEach((item: any) => {
        if (!item.dish) return;
        
        const dishId = item.dish.id;
        const current = dishMap.get(dishId);
        const itemTotal = item.quantity * (item.dish.base_price || 0);
        
        if (current) {
          current.quantity += item.quantity;
          current.revenue += itemTotal;
        } else {
          dishMap.set(dishId, {
            name: item.dish.name,
            quantity: item.quantity,
            revenue: itemTotal
          });
        }
      });

      return Array.from(dishMap.entries())
        .map(([id, details]) => ({
          id,
          name: details.name,
          quantity: details.quantity,
          revenue: details.revenue
        }))
        .sort((a, b) => b.quantity - a.quantity)
        .slice(0, limit);
    } catch (error) {
      console.error('Error in getTopDishesFallback:', error);
      return [];
    }
  }

  // ===== 4. COMANDE ATTIVE (per cucina) =====
  async getActiveComande(): Promise<any[]> {
    try {
      const restaurantId = await this.getCurrentRestaurantId();
      if (!restaurantId) return [];

      const { data, error } = await this.supabaseService.getSupabaseClient()
        .from('comande')
        .select(`
          *,
          table:table_id (table_number, table_name),
          order_header:order_header_id (order_number, customer_name),
          order_items (
            id,
            dish_id,
            quantity,
            status
          )
        `)
        .eq('restaurant_id', restaurantId)
        .in('status', ['ordered', 'waiting', 'preparing', 'ready'])
        .order('created_at', { ascending: false })
        .limit(10);

      if (error) throw error;

      return (data || []).map(comanda => ({
        ...comanda,
        order_number: comanda.order_header?.order_number || `CMD-${comanda.id.slice(-6)}`,
        total_amount: Number(comanda.total_amount) || 0
      }));
    } catch (error) {
      console.error('Error in getActiveComande:', error);
      return [];
    }
  }

  // ===== 5. METODI HELPER =====
  private async getCurrentRestaurantId(): Promise<string | null> {
    try {
      // Implementa la logica per ottenere il restaurantId corrente
      // Ad esempio da un service di autenticazione o localStorage
      return localStorage.getItem('currentRestaurantId');
    } catch {
      return null;
    }
  }

  private generateEmptySalesData(): { day: string; amount: number }[] {
    const days = [];
    for (let i = 6; i >= 0; i--) {
      const date = new Date();
      date.setDate(date.getDate() - i);
      days.push({
        day: date.toLocaleDateString('it-IT', { weekday: 'short' }),
        amount: 0
      });
    }
    return days;
  }

  private groupSalesByDay(
    comande: any[], 
    startDate: Date, 
    endDate: Date
  ): { day: string; amount: number }[] {
    const salesByDay = new Map<string, number>();
    
    // Inizializza tutti i giorni a 0
    for (let d = new Date(startDate); d <= endDate; d.setDate(d.getDate() + 1)) {
      const dayKey = d.toISOString().split('T')[0];
      salesByDay.set(dayKey, 0);
    }
    
    // Somma le vendite
    comande.forEach(comanda => {
      const dayKey = comanda.created_at.split('T')[0];
      if (salesByDay.has(dayKey)) {
        salesByDay.set(dayKey, salesByDay.get(dayKey)! + (Number(comanda.total_amount) || 0));
      }
    });
    
    // Converti nel formato richiesto
    return Array.from(salesByDay.entries()).map(([date, amount]) => ({
      day: new Date(date).toLocaleDateString('it-IT', { weekday: 'short' }),
      amount
    }));
  }
}