import { Component, OnInit, inject } from '@angular/core';
import { CommonModule, DecimalPipe } from '@angular/common';
import { lastValueFrom } from 'rxjs';

// Services
import { IngredientService } from '../../services/Piatti/ingredient.service';
import { ReservationService } from '../../services/Prenotazioni/reservation.service';
import { ReviewService } from '../../services/review.service';
import { DishService } from '../../services/Piatti/dish.service';
import { ComandaService } from '../../services/Ordini/comanda.service';
import { StatisticsService } from '../../services/statistics.service';
import { OrderHeaderService } from '../../services/Ordini/order-header.service';
import { OrderItemService } from '../../services/Ordini/order-item.service';
import { LucideAngularModule } from 'lucide-angular';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.html',
  imports: [CommonModule, LucideAngularModule],
  styleUrls: ['./dashboard.css'],
  providers: [DecimalPipe]
})
export class Dashboard implements OnInit {
  // Statistiche principali
  todayOrders: number = 0;
  todayRevenue: number = 0;
  todayReservations: number = 0;
  upcomingReservations: number = 0;
  lowStockIngredients: number = 0;
  averageRating: number = 0;
  totalReviews: number = 0;

  // Dati grafico
  salesData: { day: string; amount: number }[] = [];

  // Piatti più venduti
  topDishes: any[] = [];

  // Prenotazioni
  upcomingReservationsList: any[] = [];

  // Ordini in corso
  currentOrders: any[] = [];

  // Alert inventario
  inventoryAlerts: any[] = [];

  private decimalPipe = inject(DecimalPipe);
  private ingredientService = inject(IngredientService);
  private reservationService = inject(ReservationService);
  private reviewService = inject(ReviewService);
  private dishService = inject(DishService);
  private orderHeaderService = inject(OrderHeaderService);
  private comandaService = inject(ComandaService);
  private orderItemService = inject(OrderItemService);
  private statisticsService = inject(StatisticsService);

async ngOnInit() {
  console.log('🚀 Dashboard ngOnInit started');
  
  // ✅ SOLUZIONE SEMPLICE: Piccolo delay per stabilizzare la change detection
  await new Promise(resolve => setTimeout(resolve, 0));
  
  console.log('⏳ Loading service started');
  
  try {
    await this.loadAllData();
    console.log('✅ loadAllData completed successfully');
  } catch (error) {
    console.error('❌ Error loading dashboard data:', error);
    this.loadSampleData();
  } finally {
    console.log('🛑 Finally block reached, stopping loading service');
    console.log('⏹️ Loading service stopped');
  }
}

  async loadAllData() {
    try {
      console.log('🔄 Loading all dashboard data...');
      
      const loadPromises = [
        this.ingredientService.loadData().then(() => console.log('✅ Ingredients loaded')),
        this.reservationService.loadRestaurantReservations().then(() => console.log('✅ Reservations loaded')),
        this.reviewService.loadData().then(() => console.log('✅ Reviews loaded')),
        this.dishService.loadData().then(() => console.log('✅ Dishes loaded'))
      ];

      await Promise.all(loadPromises);
      console.log('✅ All base data loaded successfully');

      console.log('✅ Base data loaded, updating dashboard...');
      
      await this.updateDashboardData();
      
    } catch (error) {
      console.error('❌ Error in loadAllData:', error);
      throw error;
    }
  }


async updateDashboardData() {
  console.log('📊 Starting dashboard data update');
  
  try {
    // ✅ DEBUG DETTAGLIATO - ogni step
    console.log('STEP 1: Loading today orders...');
    await this.loadTodayOrders();
    console.log('✅ STEP 1 COMPLETED');
    
    console.log('STEP 2: Loading today reservations...');
    await this.loadTodayReservations();
    console.log('✅ STEP 2 COMPLETED');
    
    console.log('STEP 3: Starting parallel load of sales data and top dishes...');
    await Promise.all([
      this.loadSalesData().then(() => console.log('✅ STEP 3a - Sales data completed')),
      this.loadTopDishes().then(() => console.log('✅ STEP 3b - Top dishes completed'))
    ]);
    console.log('✅ STEP 3 COMPLETED');
    
    console.log('STEP 4: Starting parallel load of current orders and upcoming reservations...');
    await Promise.all([
      this.loadCurrentOrders().then(() => console.log('✅ STEP 4a - Current orders completed')),
      this.loadUpcomingReservationsList().then(() => console.log('✅ STEP 4b - Upcoming reservations completed'))
    ]);
    console.log('✅ STEP 4 COMPLETED');

    console.log('STEP 5: Loading sync data...');
    this.loadLowStockIngredients();
    this.loadAverageRating();
    this.loadInventoryAlerts();
    console.log('✅ STEP 5 COMPLETED');

    console.log('📊 Dashboard data updated successfully');
  } catch (error) {
    console.error('❌ Error in updateDashboardData:', error);
    throw error;
  }
}

  async loadTodayOrders() {
    try {
      console.log('📦 Loading today orders (from order headers)...');
      const result = await this.statisticsService.getTodayOrders();
      this.todayOrders = result.count;
      this.todayRevenue = result.revenue;
      console.log(`✅ Today order headers: ${this.todayOrders}, Revenue: €${this.todayRevenue}`);
    } catch (error) {
      console.error('❌ Error loading today orders:', error);
      this.todayOrders = 0;
      this.todayRevenue = 0;
    }
  }


  async loadTodayReservations() {
    try {
      console.log('📅 Loading today reservations...');
      
      // ✅ CORREZIONE: Chiama direttamente il metodo invece di usare l'Observable
      await this.reservationService.loadRestaurantReservations();
      
      // ✅ Ora puoi usare lastValueFrom perché il Subject ha un valore
      const allRestaurantReservations = await lastValueFrom(this.reservationService.restaurantReservations$);
      
      // Usa getActiveReservations per filtrare quelle di oggi
      const todayReservations = this.reservationService.getActiveReservations(allRestaurantReservations);
      
      // Usa getFutureReservations per quelle future
      const futureReservations = this.reservationService.getFutureReservations(allRestaurantReservations);
      
      this.todayReservations = todayReservations.length;
      this.upcomingReservations = futureReservations.length;
      
      console.log(`✅ Today reservations: ${this.todayReservations}, Upcoming: ${this.upcomingReservations}`);
    } catch (error) {
      console.error('❌ Error loading today reservations:', error);
      this.todayReservations = 0;
      this.upcomingReservations = 0;
    }
  }

  loadLowStockIngredients() {
    try {
      console.log('⚠️ Loading low stock ingredients...');
      const lowStock = this.ingredientService.getLowStockIngredients();
      this.lowStockIngredients = lowStock.length;
      console.log(`✅ Low stock ingredients: ${this.lowStockIngredients}`);
    } catch (error) {
      console.error('❌ Error loading low stock ingredients:', error);
      this.lowStockIngredients = 0;
    }
  }

  loadAverageRating() {
    try {
      console.log('⭐ Loading average rating...');
      const ratingData = this.reviewService.getAverageRating();
      this.averageRating = ratingData.average;
      this.totalReviews = ratingData.count;
      console.log(`✅ Average rating: ${this.averageRating}/5 (${this.totalReviews} reviews)`);
    } catch (error) {
      console.error('❌ Error loading average rating:', error);
      this.averageRating = 0;
      this.totalReviews = 0;
    }
  }

  async loadSalesData() {
    try {
      console.log('📈 Loading sales data...');
      this.salesData = await this.statisticsService.getLast7DaysSales();
      console.log(`✅ Sales data loaded: ${this.salesData.length} days`);
    } catch (error) {
      console.error('❌ Error loading sales data:', error);
      this.salesData = this.generateSampleSalesData();
    }
  }

  async loadTopDishes() {
    try {
      console.log('🍽️ Loading top dishes...');
      this.topDishes = await this.statisticsService.getTopDishes(5);
      console.log(`✅ Top dishes loaded: ${this.topDishes.length}`);
    } catch (error) {
      console.error('❌ Error loading top dishes:', error);
      this.topDishes = [];
    }
  }

  // ✅ CORREZIONE: Nuovo metodo per caricare la lista delle prenotazioni future
  async loadUpcomingReservationsList() {
    try {
      console.log('🕒 Loading upcoming reservations list...');
      
      // Ottieni tutte le prenotazioni del ristorante e poi filtra quelle future
      const allRestaurantReservations = await lastValueFrom(this.reservationService.restaurantReservations$);
      const futureReservations = this.reservationService.getFutureReservations(allRestaurantReservations);
      
      this.upcomingReservationsList = futureReservations.slice(0, 4).map(reservation => ({
        time: reservation.reservation_time.substring(0, 5),
        customer_name: this.getCustomerName(reservation),
        party_size: reservation.party_size,
        table: this.getTableName(reservation),
        status: reservation.status
      }));
      
      console.log(`✅ Upcoming reservations list: ${this.upcomingReservationsList.length}`);
    } catch (error) {
      console.error('❌ Error loading upcoming reservations list:', error);
      this.upcomingReservationsList = [];
    }
  }

  async loadCurrentOrders() {
    try {
      console.log('🔥 Loading current comande...');
      
      const comande = await this.statisticsService.getActiveComande();
      
      console.log(`📋 Raw current comande:`, comande);
      
      const ordersWithDetails = await Promise.all(
        comande.slice(0, 4).map(async (comanda) => {
          try {
            // Conta gli order items direttamente dall'array già caricato
            const itemsCount = comanda.order_items ? comanda.order_items.length : 0;
            
            return {
              order_number: comanda.order_number || `#${comanda.id?.slice(-6) || 'N/A'}`,
              items: itemsCount,
              total: comanda.total_amount || 0,
              status: comanda.status || 'pending',
              time: this.formatTimeSince(comanda.created_at),
              customer_name: comanda.customer_name || comanda.order_header?.customer_name || 'Cliente'
            };
          } catch (itemError) {
            console.error('❌ Error processing comanda:', comanda.id, itemError);
            return {
              order_number: comanda.order_number || `#${comanda.id?.slice(-6) || 'N/A'}`,
              items: 0,
              total: comanda.total_amount || 0,
              status: comanda.status || 'pending',
              time: 'N/A',
              customer_name: 'Cliente'
            };
          }
        })
      );
      
      this.currentOrders = ordersWithDetails.filter(order => order !== null);
      console.log(`✅ Current comande processed: ${this.currentOrders.length}`);
      
    } catch (error) {
      console.error('❌ Error loading current comande:', error);
      this.currentOrders = [];
    }
  }

  loadInventoryAlerts() {
    try {
      console.log('🚨 Loading inventory alerts...');
      const lowStockIngredients = this.ingredientService.getLowStockIngredients();
      
      this.inventoryAlerts = lowStockIngredients.slice(0, 4).map(ingredient => ({
        ingredient_name: ingredient.name,
        current_stock: ingredient.current_stock,
        minimum_stock: ingredient.minimum_stock,
        unit: ingredient.units?.symbol || 'pz',
        priority: ingredient.current_stock <= ingredient.minimum_stock * 0.5 ? 'high' : 'medium'
      }));
      
      console.log(`✅ Inventory alerts: ${this.inventoryAlerts.length}`);
    } catch (error) {
      console.error('❌ Error loading inventory alerts:', error);
      this.inventoryAlerts = [];
    }
  }

  // Metodo di fallback per dati di esempio (DEBUG)
  private loadSampleData() {
    console.warn('⚠️ Using sample data for dashboard');
    
    this.todayOrders = 12;
    this.todayRevenue = 450.50;
    this.todayReservations = 8;
    this.upcomingReservations = 15;
    this.lowStockIngredients = 2;
    this.averageRating = 4.5;
    this.totalReviews = 24;
    this.salesData = this.generateSampleSalesData();
    this.topDishes = this.generateSampleTopDishes();
    this.upcomingReservationsList = this.generateSampleReservations();
    this.currentOrders = this.generateSampleOrders();
    this.inventoryAlerts = this.generateSampleAlerts();
  }

  private generateSampleSalesData() {
    const days = ['Lun', 'Mar', 'Mer', 'Gio', 'Ven', 'Sab', 'Dom'];
    return days.map(day => ({
      day,
      amount: Math.floor(Math.random() * 500) + 100
    }));
  }

  private generateSampleTopDishes() {
    return [
      { name: 'Pizza Margherita', quantity: 45, revenue: 675 },
      { name: 'Spaghetti Carbonara', quantity: 38, revenue: 570 },
      { name: 'Tagliata di Manzo', quantity: 25, revenue: 625 },
      { name: 'Insalada Cesare', quantity: 22, revenue: 198 },
      { name: 'Tiramisù', quantity: 18, revenue: 126 }
    ];
  }

  private generateSampleReservations() {
    return [
      { time: '20:00', customer_name: 'Mario Rossi', party_size: 4, status: 'confirmed', table: 'Tavolo 5' },
      { time: '20:30', customer_name: 'Laura Bianchi', party_size: 2, status: 'pending', table: 'Tavolo 2' },
      { time: '21:00', customer_name: 'Giuseppe Verdi', party_size: 6, status: 'confirmed', table: 'Tavolo 8' }
    ];
  }

  private generateSampleOrders() {
    return [
      { order_number: '#12345', items: 3, total: 45.50, status: 'preparing', time: '15 min' },
      { order_number: '#12346', items: 2, total: 28.00, status: 'ready', time: '8 min' }
    ];
  }

  private generateSampleAlerts() {
    return [
      { ingredient_name: 'Pomodori San Marzano', current_stock: 5, minimum_stock: 20, unit: 'kg', priority: 'high' },
      { ingredient_name: 'Mozzarella di Bufala', current_stock: 8, minimum_stock: 15, unit: 'pz', priority: 'medium' }
    ];
  }

  // ✅ CORREZIONE: Aggiunti metodi helper per ReservationService
  private getCustomerName(reservation: any): string {
    return this.reservationService.getCustomerName(reservation);
  }

  private getTableName(reservation: any): string {
    return this.reservationService.getTableInfo(reservation);
  }

  formatTimeSince(dateString: string): string {
    if (!dateString) return 'Ora';
    
    try {
      const now = new Date();
      const date = new Date(dateString);
      const diffInMinutes = Math.floor((now.getTime() - date.getTime()) / 60000);

      if (diffInMinutes < 1) return 'Ora';
      if (diffInMinutes < 60) return `${diffInMinutes} min`;
      const diffInHours = Math.floor(diffInMinutes / 60);
      return `${diffInHours} h`;
    } catch (error) {
      return 'Ora';
    }
  }

  get maxSales(): number {
    if (this.salesData.length === 0) return 1;
    const max = Math.max(...this.salesData.map(item => item.amount));
    return max > 0 ? max : 1;
  }

  formatNumber(value: number, digitsInfo: string = '1.2-2'): string {
    if (value === null || value === undefined) return '0';
    return this.decimalPipe.transform(value, digitsInfo) || '0';
  }

  // Metodi helper per le classi CSS
  getStatusClass(status: string): string {
    const statusMap: { [key: string]: string } = {
      'confirmed': 'chip success',
      'pending': 'chip warning', 
      'cancelled': 'chip error',
      'confermata': 'chip success',
      'in attesa': 'chip warning',
      'cancellata': 'chip error'
    };
    return statusMap[status] || 'chip';
  }

  getOrderStatusClass(status: string): string {
    const statusMap: { [key: string]: string } = {
      'preparing': 'preparing',
      'ready': 'chip success',
      'completed': 'chip inactive',
      'served': 'chip inactive',
      'received': 'chip warning'
    };
    return statusMap[status] || 'chip';
  }
}