import { Injectable } from '@angular/core';
import { BaseService } from './Base/base.service';
import { filter, take } from 'rxjs';

export interface Review {
  id: string;
  restaurant_id: string;
  customer_id: string;
  reservation_id: string;
  rating: number;
  comment?: string;
  title?: string;
  is_approved: boolean;
  response_comment?: string;
  created_at: string;
}

@Injectable({
  providedIn: 'root'
})
export class ReviewService extends BaseService<Review> {
  constructor() {
    super();
    this.authService.currentUser$
      .pipe(filter(u => !!u), take(1))
      .subscribe(() => {
        this.loadData();
      });
  }

  override getTableName(): string {
    return 'reviews';
  }

  // ✅ Override per ordinamento personalizzato
  override async loadData(additionalFilters?: any): Promise<void> {
    try {
      this.loadingSubject.next(true);
      const restaurantId = await this.getCurrentRestaurantId();
      
      if (!restaurantId) {
        this.dataSubject.next([]);
        this.loadingSubject.next(false);
        return;
      }

      const { data: reviews, error } = await this.supabaseService.getSupabaseClient()
        .from(this.getTableName())
        .select('*')
        .eq('restaurant_id', restaurantId)
        .order('created_at', { ascending: false });

      if (error) throw error;

      console.log('Reviews loaded:', reviews?.length);
      this.dataSubject.next(reviews || []);
      
    } catch (error) {
      console.error('Error loading reviews:', error);
      this.handleError('loadData', error);
    } finally {
      this.loadingSubject.next(false);
    }
  }

  // ✅ Mantieni i metodi specifici
  getAverageRating(): { average: number, count: number } {
    const reviews = this.dataSubject.value;
    if (reviews.length === 0) {
      return { average: 0, count: 0 };
    }

    const total = reviews.reduce((sum, review) => sum + review.rating, 0);
    const average = total / reviews.length;
    return { average: Math.round(average * 10) / 10, count: reviews.length };
  }

  // ✅ ALIAS per compatibilità
  async loadReviews(): Promise<void> {
    return this.loadData();
  }
}